import React, { useCallback, useMemo, useState } from 'react';
import { LinErpListFilterBar, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd, parseReportStt } from '../../../utils/formatters';
import { YEAR_OPTIONS } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { B03Row } from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-b03-dn';
const PAGE_ID = 'baocao-b03-dn';

const B03DnPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [year, setYear] = useState(now.getFullYear());
  const [rows, setRows] = useState<B03Row[]>([]);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    analyticsService
      .getB03Dn({ year })
      .then(setRows)
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [year, dispatch]);

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        onDateChange={() => {}}
        onSearch={handleLoad}
        searchAriaLabel="Xem"
        loading={loading}
        leading={(
          <div data-testid={`${TEST_ID}-field-year`}>
            <Select label="Năm" value={String(year)} onChange={e => setYear(Number(e.target.value))} options={YEAR_OPTIONS} size="small" />
          </div>
        )}
      />
    ),
    [year, handleLoad, loading],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="B03-DN — Báo cáo lưu chuyển tiền tệ"
      loading={loading}
      hasData={rows.length > 0}
      filters={listFilters}
      onLoad={handleLoad}
      exportPath="/reports/financial/b03-dn/export-excel"
      exportParams={{ year }}
      exportFilename={`B03-T${year}.xlsx`}
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            <th className={reportStyles.colStt}>STT</th>
            <th>Chỉ tiêu</th>
            <th className={reportStyles.colStt}>Mã số</th>
            <th className={reportStyles.colStt}>Thuyết minh</th>
            <th className={reportStyles.colRight}>Năm nay</th>
            <th className={reportStyles.colRight}>Năm trước</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => {
            let className = '';
            if (r.isTotal) className = reportStyles.rowTotal;
            else if (r.indent === 0 && !r.isTotal) className = reportStyles.rowSectionHead;
            const padLeft = r.indent ? r.indent * 20 : 0;
            const { stt, label } = parseReportStt(r.name);
            return (
              <tr key={i} className={className}>
                <td className={reportStyles.colStt}>{stt}</td>
                <td style={{ paddingLeft: `${12 + padLeft}px` }}>{label}</td>
                <td className={reportStyles.colStt}>{r.code}</td>
                <td className={reportStyles.colStt}>{''}</td>
                <td className={reportStyles.colRight}>{formatVnd(r.currentAmount)}</td>
                <td className={reportStyles.colRight}>{formatVnd(r.previousAmount)}</td>
              </tr>
            );
          })}
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default B03DnPage;
